// 注意这里的类名，要和主文件里 YFJ_Module_ + ucfirst('bazi_cesuan') 对应
class YFJ_Module_Zhanbu_xingzuo extends YFJ_Base_Module {

    public function __construct() {
        $this->module_id = 'zhanbu_xingzuo';             // 1. 修改模块 ID
        $this->shortcode = 'yfj_zhanbu_xingzuo';         // 2. 修改短代码
        $this->api_endpoint = '/v1/Zhanbu/yunshi';       // 3. 配置对应的真实 API 接口

        parent::__construct();
    }

    /**
     * 【星座运势专属：结合当天的瞬态缓存策略】
     * 解决跨天缓存失效问题
     */
    protected function fetch_api_data($api_url, $payload) {
        // 1. 获取请求类型和星座ID
        $type = $payload['type'] ?? '0'; // 0: 星座, 1: 生肖
        $yunshi_id = $payload['title_yunshi'] ?? '';

        if ($yunshi_id === '') {
            return parent::fetch_api_data($api_url, $payload);
        }

        // 2. 获取当前的本地年月日 (使用 WP 函数防时区错乱)
        $today = current_time('Ymd');

        // 3. 生成带日期的 Cache Key (例: yfj_xz_20260503_t0_id3)
        // 跨过零点后，$today 发生改变，自动生成全新的 Key
        $cache_key = 'yfj_xz_' . $today . '_t' . $type . '_id' . $yunshi_id;

        // 4. 读取本地瞬态缓存
        $cached_body = get_transient($cache_key);

        if (false !== $cached_body) {
            // 命中当天的缓存，直接返回
            return $cached_body;
        }

        // 5. 未命中（或者是新的一天首次请求），请求服务器
        $body = parent::fetch_api_data($api_url, $payload);

        // 6. 校验通过，写入缓存
        // 依然可以保持 3 小时的刷新频率（防备接口白天更新内容），同时靠 Key 保证零点强制刷新
        if ($body && isset($body['errcode']) && $body['errcode'] == 0) {
            set_transient($cache_key, $body, 3 * HOUR_IN_SECONDS);
        }

        return $body;
    }

    /**
     * 专属数据拦截与加工引擎 (重写基类方法)
     * 在这里可以对 API 返回的原始数据进行格式化、过滤或追加二次计算的自定义数据。
     */
    protected function process_api_data($raw_data) {
        // 1. 确保数据是数组格式，防止报错
        if (is_array($raw_data)) {
            //如果 API 没返回格局，给个默认的兜底值
            if (!isset($raw_data['base_info']['zhengge'])) {
                $raw_data['base_info']['zhengge'] = '未入格';
            }
        }

        //将处理后的数据返回给 views/result.php 进行渲染
        return $raw_data;
    }

